/** Devuelve copia con array tal como lo entrega Supabase */
export function getPlantillasConsentLocales() {
  return PLANTILLAS_CONSENT_LOCALES.map(p => ({ ...p }))
}

/** Mezcla resultados de Supabase con plantillas locales (Supabase tiene prioridad por slug). */
export function mergePlantillasConsent(remotas) {
  const base = new Map(PLANTILLAS_CONSENT_LOCALES.map(p => [p.slug, { ...p }]))
  for (const r of remotas || []) {
    if (!r || !r.slug) continue
    const prev = base.get(r.slug) || {}
    const cuerpo = (r.cuerpo_texto && String(r.cuerpo_texto).trim()) ? r.cuerpo_texto : prev.cuerpo_texto
    base.set(r.slug, { ...prev, ...r, cuerpo_texto: cuerpo })
  }
  return Array.from(base.values()).sort((a, b) =>
    String(a.categoria || '').localeCompare(String(b.categoria || '')) ||
    String(a.titulo || '').localeCompare(String(b.titulo || ''))
  )
}
